  "semiologie:saussure": [
    { id: "fx-sa1", front: "Le naming 'Petit Bateau' pour une marque de vetements enfants : analysez avec Saussure.", back: "SIGNIFIANT : les mots 'Petit Bateau'. SIGNIFIE : un petit navire. Mais le lien avec les vetements est ARBITRAIRE (convention de marque). Le nom evoque l'enfance, le jeu, la comptine — c'est la CONNOTATION culturelle qui fait le lien, pas un rapport naturel.", difficulty: "hard", tags: ["saussure", "naming", "application"] },
    { id: "fx-sa2", front: "Pourquoi le naming 'Amazon' est-il efficace selon Saussure ?", back: "SIGNIFIANT : 'Amazon'. SIGNIFIE primaire : le fleuve Amazone (le plus grand du monde). Par CONNOTATION : immense, tout, exotique, nature. Le lien avec un site e-commerce est ARBITRAIRE mais le signifie evoque l'abondance et la demesure = valeurs de la marque.", difficulty: "hard", tags: ["saussure", "naming", "application"] },
    { id: "fx-sa3", front: "Expliquez l'axe syntagmatique et paradigmatique avec un slogan pub.", back: "Slogan 'Just Do It'. AXE SYNTAGMATIQUE (horizontal) : l'ordre Just + Do + It cree le sens. AXE PARADIGMATIQUE (vertical) : on aurait pu choisir 'Simply' au lieu de 'Just', 'Try' au lieu de 'Do'. Chaque MOT est un CHOIX parmi d'autres possibles.", difficulty: "hard", tags: ["saussure", "syntagme", "paradigme"] },
    { id: "fx-sa4", front: "Piege BTS : Saussure etudie-t-il les IMAGES publicitaires ?", back: "NON. Saussure etudie le signe LINGUISTIQUE (mots, langage). Pour les images, c'est BARTHES (rhetorique de l'image) et PEIRCE (icone/indice/symbole). Saussure est utile en pub pour analyser le NAMING, les SLOGANS et les textes, pas les visuels.", difficulty: "medium", tags: ["saussure", "limites", "pieges"] },
  ],

  "semiologie:barthes": [
    { id: "fx-ba1", front: "Analysez une pub Chanel N°5 avec les 3 niveaux de Barthes.", back: "LINGUISTIQUE : 'Chanel N°5' (marque, nom iconique). DENOTE : un flacon dore, une femme elegante, fond noir. CONNOTE : luxe (or, noir), feminite sophistiquee, intemporalite, mystere, seduction. Le message connote est INTENTIONNEL : chaque element est choisi pour evoquer le prestige.", difficulty: "hard", tags: ["barthes", "analyse", "chanel"] },
    { id: "fx-ba2", front: "Analysez une pub Coca-Cola de Noel avec Barthes.", back: "LINGUISTIQUE : logo Coca-Cola, 'Open Happiness'. DENOTE : Pere Noel, bouteille rouge, neige, famille souriante. CONNOTE : chaleur familiale, tradition, partage, bonheur, americanite. Fun fact : Coca-Cola a POPULARISE le Pere Noel rouge en 1931 — la connotation est devenue culture.", difficulty: "hard", tags: ["barthes", "analyse", "coca-cola"] },
    { id: "fx-ba3", front: "Analysez un catalogue IKEA avec les niveaux de Barthes.", back: "LINGUISTIQUE : noms suedois (Kallax, Billy), prix. DENOTE : meubles, pieces, objets. CONNOTE : design accessible, modernite scandinave, vie quotidienne idealisee, democratisation du beau. L'usage de VRAIS interieurs (pas de studio) CONNOTE l'authenticite.", difficulty: "hard", tags: ["barthes", "analyse", "ikea"] },
    { id: "fx-ba4", front: "Piege BTS : denotation et connotation sont-elles toujours separables ?", back: "NON. Barthes lui-meme montre que la denotation 'pure' n'existe pas vraiment en publicite : meme la description 'objective' est orientee par des choix (cadrage, lumiere, couleurs). La denotation est un 'alibi naturalisant' de la connotation. Tout est INTENTIONNEL en pub.", difficulty: "hard", tags: ["barthes", "pieges", "theorie"] },
    { id: "fx-ba5", front: "Qu'est-ce que le 'mythe' selon Barthes et comment s'applique-t-il a la pub ?", back: "Le MYTHE est un systeme semiologique SECOND : le signe connote devient lui-meme signifiant d'un nouveau signifie. Exemple : la 'francite' (mythes de Barthes) = baguette+beret+tour Eiffel. En pub : Evian utilise le mythe de la 'purete alpine' (montagne+source+bebe = jeunesse eternelle).", difficulty: "hard", tags: ["barthes", "mythe", "avance"] },
    { id: "fx-ba6", front: "Comment Barthes analyserait-il une pub Instagram avec filtre vintage ?", back: "Le FILTRE vintage est un choix semiologique INTENTIONNEL. DENOTE : image legerement jaunie, grain. CONNOTE : nostalgie, authenticite, artisanat, 'fait maison'. C'est une CONNOTATION TECHNIQUE : le traitement de l'image EST un message. Barthes dirait que meme le style 'naturel' est code.", difficulty: "hard", tags: ["barthes", "digital", "application"] },
  ],

  "semiologie:peirce": [
    { id: "fx-pe1", front: "Le logo Apple (pomme croquee) : icone, indice ou symbole ? Argumentez.", back: "C'est un ICONE (ressemble a une pomme) ET un SYMBOLE (le lien pomme-technologie est conventionnel/arbitraire). La morsure (bite/byte) ajoute une dimension SYMBOLIQUE (jeu de mots, connaissance/pomme d'Eve). Un signe peut appartenir a PLUSIEURS categories.", difficulty: "hard", tags: ["peirce", "application", "apple"] },
    { id: "fx-pe2", front: "Classez ces elements publicitaires selon Peirce : emoji coeur, photo produit, fumee sur un cafe, logo Nike.", back: "Emoji coeur = SYMBOLE (convention). Photo produit = ICONE (ressemblance). Fumee sur un cafe = INDICE (consequence naturelle de la chaleur). Logo Nike (virgule) = SYMBOLE (lien arbitraire avec la marque), mais aussi ICONE (ressemble a un mouvement, une aile).", difficulty: "hard", tags: ["peirce", "classification", "pub"] },
    { id: "fx-pe3", front: "Les emojis sont-ils des icones, des indices ou des symboles selon Peirce ?", back: "C'est COMPLEXE. Un emoji smiley = ICONE (ressemble a un visage). Un emoji coeur = SYMBOLE (convention culturelle). Un emoji flamme = peut etre ICONE (ressemble a du feu) et SYMBOLE (signifie 'tendance/hot'). Les emojis montrent que les categories de Peirce ne sont pas etanches.", difficulty: "hard", tags: ["peirce", "digital", "emojis"] },
    { id: "fx-pe4", front: "En publicite automobile, les gouttes d'eau sur la carrosserie sont quel type de signe (Peirce) ?", back: "Un INDICE : les gouttes sont la consequence naturelle de la pluie/lavage = fraicheur, proprete, nouveaute. Mais c'est un indice FABRIQUE (mis en scene intentionnellement). En pub, les indices naturels sont souvent SIMULES pour produire une connotation de verite.", difficulty: "hard", tags: ["peirce", "pub", "indice"] },
  ],

  // =====================================================================
