  "rhetorique:figures-style": [
    { id: "fx-rh1", front: "'L'Oreal : Parce que vous le valez bien' — quelle figure de style ?", back: "C'est un ARGUMENT D'AUTORITE INVERSE : au lieu de dire 'les experts le recommandent' (autorite externe), on dit 'VOUS le valez' (autorite du consommateur sur lui-meme). On pourrait aussi y voir une forme de LITOTE (sous-entend que vous meritez le meilleur). Ce n'est PAS une anaphore (pas de repetition en debut).", difficulty: "hard", tags: ["rhetorique", "loreal", "analyse"] },
    { id: "fx-rh2", front: "'Red Bull te donne des ailes' — pourquoi est-ce une metaphore et PAS une hyperbole ?", back: "METAPHORE : comparaison implicite entre l'energie et les ailes (assimilation directe, sans 'comme'). Ce n'est PAS une hyperbole car on ne dit pas 'Red Bull te donne ENORMEMENT d'energie' (exageration quantitative). On SUBSTITUE un concept par une image. La metaphore TRANSFORME, l'hyperbole EXAGERE.", difficulty: "hard", tags: ["rhetorique", "metaphore", "distinction"] },
    { id: "fx-rh3", front: "'Petit prix, grand plaisir' — analysez les figures de style combinees.", back: "ANTITHESE : opposition petit/grand. CHIASME partiel : structure en miroir (adjectif+nom / adjectif+nom, avec inversion de la valeur). PARONOMASE legere : proximite sonore prix/plaisir. En pub, les figures se COMBINENT pour maximiser l'impact memoriel.", difficulty: "hard", tags: ["rhetorique", "antithese", "combinaison"] },
    { id: "fx-rh4", front: "'Achetez un Mac, offrez-vous la liberte' — identifiez la figure.", back: "METONYMIE : 'Mac' remplace 'ordinateur Apple' (la marque pour le produit). 'Liberte' est aussi une metonymie/metaphore : un objet materiel est associe a un concept abstrait. On pourrait aussi y voir un ZEUGME (lier un objet concret et un concept abstrait par le meme verbe 'offrir').", difficulty: "hard", tags: ["rhetorique", "metonymie", "apple"] },
    { id: "fx-rh5", front: "'Nespresso. What else?' — quelles figures de style ?", back: "QUESTION RHETORIQUE (la reponse est evidente : rien d'autre). LITOTE (en disant 'quoi d'autre ?', on sous-entend 'il n'y a rien de mieux'). ELLIPSE (phrase nominale ultra-courte). La BRIEVETE meme est un procede stylistique qui connote l'evidence.", difficulty: "hard", tags: ["rhetorique", "nespresso", "analyse"] },
    { id: "fx-rh6", front: "'Impossible is Nothing' (Adidas) — analysez les figures.", back: "PARADOXE / ANTITHESE : 'impossible' (negatif absolu) est reduit a 'nothing' (neant). INVERSION syntaxique : en anglais normal, on dirait 'Nothing is impossible'. Le placement de 'Impossible' en premier cree un EFFET DE SURPRISE puis de resolution. C'est aussi un SOLECISME volontaire stylistique.", difficulty: "hard", tags: ["rhetorique", "adidas", "paradoxe"] },
    { id: "fx-rh7", front: "'Think Different' (Apple) — pourquoi est-ce un solecisme volontaire ?", back: "En anglais correct : 'Think Differently' (adverbe). Apple utilise 'Different' (adjectif) au lieu de l'adverbe = SOLECISME (faute grammaticale volontaire). Effet : transgression de la norme = on est DIFFERENT meme dans le langage. C'est aussi une INJONCTION (imperatif) = fonction CONATIVE.", difficulty: "hard", tags: ["rhetorique", "apple", "solecisme"] },
    { id: "fx-rh8", front: "'Connecting People' (Nokia) — quelles figures et fonctions ?", back: "METONYMIE : 'People' (les gens) remplace 'utilisateurs de telephones'. Le participe present 'Connecting' = action CONTINUE (pas ponctuelle). C'est aussi une SYNECDOQUE : le telephone (partie) represente la relation humaine (tout). Fonction Jakobson dominante : PHATIQUE (maintien du contact).", difficulty: "hard", tags: ["rhetorique", "nokia", "metonymie"] },
  ],

