  "argumentation:convaincre-persuader": [
    { id: "fx-ar1", front: "Identifiez ethos/pathos/logos dans une pub Dove 'Real Beauty'.", back: "ETHOS : Dove se positionne comme marque 'authentique' et bienveillante (credibilite morale). PATHOS : emotion forte (femmes ordinaires qui s'acceptent, temoignages touchants). LOGOS quasi absent : pas de chiffres ni de preuves scientifiques. Dove mise a 80% sur le PATHOS.", difficulty: "hard", tags: ["argumentation", "ethos-pathos-logos", "dove"] },
    { id: "fx-ar2", front: "Pub Colgate : '9 dentistes sur 10 recommandent Colgate'. Ethos, pathos ou logos ?", back: "ETHOS (credibilite des experts dentistes) + LOGOS (statistique '9 sur 10' = preuve chiffree). Attention piege : le chiffre ressemble a du logos mais c'est surtout de l'ETHOS (argument d'autorite). Un vrai logos serait 'reduit les caries de 50% prouve en laboratoire'.", difficulty: "hard", tags: ["argumentation", "ethos", "logos"] },
    { id: "fx-ar3", front: "Piege BTS : une pub peut-elle UNIQUEMENT convaincre sans persuader ?", back: "En theorie oui (pub informative pure avec faits et chiffres), mais en PRATIQUE non. Toute pub utilise des elements de persuasion (choix des couleurs, musique, mise en scene = pathos). Meme un tableau comparatif 'objectif' est une MISE EN SCENE persuasive. Convaincre et persuader sont toujours MELES.", difficulty: "hard", tags: ["argumentation", "pieges", "distinction"] },
    { id: "fx-ar4", front: "Comment Apple utilise-t-il les 3 moyens d'Aristote dans ses keynotes ?", back: "ETHOS : Tim Cook/Steve Jobs = figures charismatiques, credibles, passionnees. PATHOS : storytelling emotionnel ('this changes everything'), musique, applaudissements. LOGOS : benchmarks, specs techniques, demos en direct. L'ORDRE est strategique : ethos d'abord, puis pathos, logos en soutien.", difficulty: "hard", tags: ["argumentation", "apple", "application"] },
    { id: "fx-ar5", front: "La difference entre ARGUMENT et MANIPULATION : ou est la limite en pub ?", back: "ARGUMENT = raisonnement transparent (on peut le verifier/contester). MANIPULATION = dissimulation de l'intention (le recepteur ne sait pas qu'on l'influence). La pub est dans une zone grise : elle PERSUADE ouvertement (on sait que c'est une pub) mais utilise des techniques de manipulation (biais cognitifs, peur, urgence artificielle).", difficulty: "hard", tags: ["argumentation", "ethique", "manipulation"] },
  ],

