  "theories-communication:shannon-weaver": [
    { id: "qx-sh1", question: "Un gresilement lors d'un appel telephonique est un exemple de :", options: ["Bruit semantique", "Bruit technique", "Bruit organisationnel", "Feedback negatif"], correctIndex: 1, explanation: "Bruit TECHNIQUE : perturbation physique du signal (gresilement, coupure). Le bruit semantique serait un mot mal compris. Le bruit organisationnel serait une hierarchie qui filtre l'info. Le feedback n'existe PAS dans le modele de Shannon.", difficulty: "easy", tags: ["shannon", "bruit"] },
    { id: "qx-sh2", question: "Quel modele serait le plus adapte pour analyser un chatbot de service client ?", options: ["Shannon (lineaire)", "Lasswell (5W)", "Palo Alto (systemique)", "Shannon suffit largement"], correctIndex: 2, explanation: "Un chatbot est INTERACTIF (question-reponse = feedback), il s'adapte au contexte de l'utilisateur = approche SYSTEMIQUE de Palo Alto. Shannon est trop lineaire (pas de feedback). Lasswell ne capte pas l'interactivite.", difficulty: "hard", tags: ["shannon", "palo-alto", "application"] },
  ],

  "theories-communication:lasswell": [
    { id: "qx-la1", question: "Dans le modele de Lasswell, 'par quel canal' correspond a :", options: ["Le contenu du message", "Le medium utilise", "La reaction du public", "L'emetteur du message"], correctIndex: 1, explanation: "'Par quel canal' (Which channel) = le MEDIUM utilise pour transmettre le message (TV, radio, presse, digital, affichage...). Le contenu = 'Dit quoi'. La reaction = 'Avec quel effet'. L'emetteur = 'Qui'.", difficulty: "easy", tags: ["lasswell", "5W"] },
    { id: "qx-la2", question: "Lasswell et Shannon ont en commun :", options: ["L'analyse du feedback", "L'approche systemique", "Un modele lineaire sans retour", "L'etude de la connotation"], correctIndex: 2, explanation: "Les deux modeles sont LINEAIRES et sans feedback. Shannon analyse la transmission technique, Lasswell analyse l'effet du message. Ni l'un ni l'autre n'est systemique (c'est Palo Alto) ni ne traite de connotation (c'est Barthes).", difficulty: "medium", tags: ["lasswell", "shannon", "comparaison"] },
    { id: "qx-la3", question: "Lasswell a concu son modele pour analyser principalement :", options: ["La communication interpersonnelle", "La communication non-verbale", "La propagande et la communication de masse", "Le langage poetique"], correctIndex: 2, explanation: "Lasswell etait un specialiste de la PROPAGANDE pendant la Seconde Guerre mondiale. Son modele des 5W a ete concu pour analyser l'efficacite de la communication de MASSE et de la propagande de guerre.", difficulty: "easy", tags: ["lasswell", "propagande", "histoire"] },
  ],

  "theories-communication:jakobson": [
    { id: "qx-ja1", question: "Un panneau publicitaire 'SOLDES — Jusqu'a -70%' releve principalement de quelle fonction ?", options: ["Poetique (forme attractive)", "Referentielle (information factuelle)", "Conative (inciter a agir)", "Emotive (exprimer une emotion)"], correctIndex: 2, explanation: "Fonction CONATIVE dominante : le but est de faire AGIR le consommateur (venir acheter). La fonction referentielle est presente (-70% = info) mais secondaire. L'objectif principal est l'ACTION, pas l'information.", difficulty: "medium", tags: ["jakobson", "application"] },
    { id: "qx-ja2", question: "Les notifications push d'une application relevent de la fonction :", options: ["Metalinguistique", "Phatique", "Referentielle", "Poetique"], correctIndex: 1, explanation: "Fonction PHATIQUE : les notifications MAINTIENNENT LE CONTACT entre l'appli et l'utilisateur. Elles rappellent que le canal est ouvert. Meme les notifs sans contenu reel ('Vous nous manquez !') sont phatiques.", difficulty: "hard", tags: ["jakobson", "phatique", "digital"] },
    { id: "qx-ja3", question: "Quelle combinaison de fonctions est la plus efficace en publicite ?", options: ["Referentielle + metalinguistique", "Conative + poetique + emotive", "Phatique + metalinguistique", "Referentielle + phatique"], correctIndex: 1, explanation: "CONATIVE (faire agir) + POETIQUE (forme memorable) + EMOTIVE (connexion emotionnelle) = le trio gagnant en pub. La referentielle est utile mais pas suffisante seule. La metalinguistique est rare en pub.", difficulty: "hard", tags: ["jakobson", "pub", "strategie"] },
  ],

  "theories-communication:palo-alto": [
    { id: "qx-pa1", question: "Selon Palo Alto, une marque qui ne communique pas pendant une crise :", options: ["Ne communique pas du tout", "Communique malgre elle (le silence est interprete)", "Respecte la regle de non-communication", "Applique la strategie du silence efficace"], correctIndex: 1, explanation: "'On ne peut pas ne pas communiquer'. Le SILENCE est interprete : mepris, culpabilite, arrogance. L'absence de communication EST une forme de communication, et souvent une mauvaise. Il n'existe pas de 'non-communication'.", difficulty: "medium", tags: ["palo-alto", "crise", "application"] },
    { id: "qx-pa2", question: "La metacommunication selon Palo Alto designe :", options: ["La communication sur internet", "La communication sur la relation entre interlocuteurs", "L'etude des medias", "La communication non-verbale uniquement"], correctIndex: 1, explanation: "Metacommunication = communication SUR LA COMMUNICATION, sur la RELATION entre les interlocuteurs. Exemple : 'C'est un ordre' definit une relation hierarchique. Tout message contient un contenu (info) ET une relation (comment le prendre).", difficulty: "hard", tags: ["palo-alto", "metacommunication"] },
    { id: "qx-pa3", question: "Pour analyser une campagne virale sur TikTok, le modele le plus pertinent est :", options: ["Shannon (transmission du signal)", "Lasswell (5 questions)", "Jakobson (6 fonctions)", "Palo Alto (approche systemique)"], correctIndex: 3, explanation: "TikTok est un SYSTEME interactif : chaque utilisateur cree, partage, commente, influence les autres. L'algorithme creer des boucles de feedback. C'est l'approche SYSTEMIQUE de Palo Alto qui capte cette complexite. Shannon est trop lineaire, Lasswell trop simplifie.", difficulty: "hard", tags: ["palo-alto", "digital", "tiktok"] },
  ],

  // =====================================================================
  // E1 — SEMIOLOGIE (+8 quiz)
