  "rhetorique:figures-style": [
    { id: "qx-rh1", question: "'Venez comme vous etes' (McDonald's) est principalement :", options: ["Une metaphore", "Une litote", "Une invitation (fonction conative) + antiphrase", "Une hyperbole"], correctIndex: 2, explanation: "C'est une INVITATION directe (fonction conative = faire venir). On peut y voir une LITOTE : en disant 'comme vous etes' (sans effort), on sous-entend 'nous vous acceptons tous' (message d'inclusion fort). Ce n'est ni une metaphore, ni une hyperbole, ni une antiphrase.", difficulty: "hard", tags: ["rhetorique", "mcdonalds", "analyse"] },
    { id: "qx-rh2", question: "'Think Different' utilise un solecisme volontaire. Un solecisme est :", options: ["Une exageration", "Une faute de syntaxe/grammaire volontaire", "Un jeu de mots", "Une repetition"], correctIndex: 1, explanation: "SOLECISME = faute de syntaxe ou grammaire VOLONTAIRE a des fins stylistiques. 'Different' (adjectif) au lieu de 'Differently' (adverbe). La transgression grammaticale EST le message : on est different meme dans la facon de parler.", difficulty: "hard", tags: ["rhetorique", "solecisme", "apple"] },
    { id: "qx-rh3", question: "Quelle figure de style domine dans les slogans de luxe comme 'J'adore' (Dior) ?", options: ["Hyperbole (exageration)", "Ellipse (brievete extreme)", "Accumulation", "Comparaison"], correctIndex: 1, explanation: "ELLIPSE : 'J'adore' tout court, sans complement. L'objet de l'adoration est OMIS volontairement. Cette brievete extreme cree du MYSTERE et de l'ELEGANCE. Le luxe communique souvent par ellipse : moins on dit, plus on suggere.", difficulty: "hard", tags: ["rhetorique", "ellipse", "luxe"] },
    { id: "qx-rh4", question: "'Un diamant est eternel' (De Beers) est :", options: ["Une hyperbole (exageration)", "Une metaphore (le diamant = l'amour)", "Les deux a la fois", "Une comparaison"], correctIndex: 2, explanation: "HYPERBOLE ('eternel' = exageration, rien n'est vraiment eternel) + METAPHORE (le diamant represente l'amour eternel par assimilation implicite). Les figures se COMBINENT souvent en pub pour maximiser l'impact.", difficulty: "hard", tags: ["rhetorique", "combinaison", "de-beers"] },
    { id: "qx-rh5", question: "Jacques Durand explique que la pub aime les figures de rhetorique car :", options: ["Elles sont gratuites a utiliser", "Elles procurent du plaisir par la transgression", "Elles sont obligatoires legalement", "Elles facilitent la traduction internationale"], correctIndex: 1, explanation: "Durand montre que les figures creent du PLAISIR par la TRANSGRESSION : accepter une metaphore ('des ailes' pour de l'energie) = plaisir intellectuel de decoder. La pub nous fait accepter des absurdites impossibles dans la vie reelle (taureau volant, voiture sur l'eau).", difficulty: "medium", tags: ["rhetorique", "durand", "theorie"] },
    { id: "qx-rh6", question: "Un CHIASME est une structure en :", options: ["Repetition AA-AA", "Miroir AB-BA", "Gradation A-B-C", "Opposition A vs B"], correctIndex: 1, explanation: "Chiasme = structure en MIROIR AB-BA. Exemple : 'Bonheur de vivre, vivre de bonheur'. Les elements sont CROISES. Difference avec l'anaphore (repetition en debut AA) et l'antithese (opposition A vs B sans croisement).", difficulty: "medium", tags: ["rhetorique", "chiasme"] },
    { id: "qx-rh7", question: "'Fraicheur, saveur, douceur, bonheur' est une :", options: ["Gradation", "Accumulation", "Anaphore", "Chiasme"], correctIndex: 1, explanation: "ACCUMULATION : enumeration de termes (effet d'abondance). Ce n'est pas une gradation car il n'y a pas de progression croissante claire (les termes ne vont pas du plus faible au plus fort). L'accumulation MULTIPLIE les qualites pour creer un effet d'abondance.", difficulty: "medium", tags: ["rhetorique", "accumulation"] },
    { id: "qx-rh8", question: "Identifiez la figure : 'La France a peur' (pour : les Francais ont peur).", options: ["Metonymie", "Synecdoque", "Personnification", "Hyperbole"], correctIndex: 0, explanation: "METONYMIE : 'La France' (le pays) remplace 'les Francais' (les habitants). Le contenant (pays) pour le contenu (habitants). On pourrait aussi argumenter une PERSONNIFICATION (la France 'a peur' = emotion humaine attribuee a un pays), mais la metonymie est plus precise.", difficulty: "hard", tags: ["rhetorique", "metonymie"] },
  ],

