  "veille-operationnelle:types-veille": [
    { id: "qx-ve1", question: "La veille CREATIVE consiste a :", options: ["Surveiller les prix des concurrents", "Suivre les tendances graphiques et les innovations creatives", "Verifier la conformite legale des campagnes", "Analyser les bilans financiers"], correctIndex: 1, explanation: "Veille CREATIVE = tendances graphiques, nouvelles formes de communication, benchmarks creatifs, innovations visuelles. C'est different de la veille concurrentielle (prix, offres) ou juridique (lois). Outils : Behance, Dribbble, Awwwards, Pinterest.", difficulty: "easy", tags: ["veille", "creative"] },
    { id: "qx-ve2", question: "Brandwatch est un outil de :", options: ["Creation graphique", "Social listening et analyse de sentiment", "Comptabilite", "Envoi d'e-mailing"], correctIndex: 1, explanation: "Brandwatch = outil de SOCIAL LISTENING : il analyse les mentions de la marque sur les RS, mesure le SENTIMENT (positif/negatif/neutre), identifie les tendances et les insights consommateurs. C'est un outil de veille e-reputation avance.", difficulty: "medium", tags: ["veille", "outils", "brandwatch"] },
    { id: "qx-ve3", question: "Pour surveiller les mots-cles SEO de vos concurrents, l'outil le plus adapte est :", options: ["Google Alerts", "Feedly", "SEMrush", "Brandwatch"], correctIndex: 2, explanation: "SEMrush analyse specifiquement le SEO/SEA : mots-cles positionnes, trafic estime, backlinks, depenses publicitaires des concurrents. Google Alerts surveille les mentions. Feedly agregue du contenu. Brandwatch ecoute les RS.", difficulty: "medium", tags: ["veille", "outils", "semrush"] },
    { id: "qx-ve4", question: "La veille doit etre :", options: ["Ponctuelle et reactive", "Organisee et continue", "Uniquement digitale", "Realisee par le directeur general"], correctIndex: 1, explanation: "La veille est par definition ORGANISEE (methodique, structuree) et CONTINUE (permanente, pas ponctuelle). Elle peut etre digitale ET analogique (salons, conferences). Elle est realisee par le service communication ou marketing, pas forcément par la direction.", difficulty: "easy", tags: ["veille", "definition"] },
    { id: "qx-ve5", question: "Quelle veille le RGPD impacte-t-il le plus directement ?", options: ["Veille creative", "Veille technologique", "Veille juridique", "Veille concurrentielle"], correctIndex: 2, explanation: "Le RGPD (protection des donnees personnelles) est une REGLEMENTATION = veille JURIDIQUE. Il impacte aussi la veille technologique (outils conformes) et concurrentielle (comment les concurrents s'adaptent), mais il releve en premier lieu du LEGAL.", difficulty: "easy", tags: ["veille", "juridique", "rgpd"] },
  ],

  // =====================================================================
